// @ts-nocheck
import { useState, useMemo } from 'react';
import {
  Box,
  Typography,
  Button,
  IconButton,
  Dialog,
  Tooltip,
  makeStyles,
  useTheme,
} from '@material-ui/core';
import CloseIcon from '@material-ui/icons/Close';
import OpenInNewIcon from '@material-ui/icons/OpenInNew';
import CodeIcon from '@material-ui/icons/Code';
import VisibilityOffOutlinedIcon from '@material-ui/icons/VisibilityOffOutlined';
import VisibilityOutlinedIcon from '@material-ui/icons/VisibilityOutlined';
import {
  type QualityViolation,
  type SeverityClass,
  SEVERITY_COLORS,
} from './qualityDemoData';
import { DEMO_CODE_CONTEXT } from './QualityTab';

const FILLED_SEVERITY: Record<string, { bg: string; color: string }> = {
  critical: { bg: '#a30000', color: '#fff' },
  high: { bg: '#c9190b', color: '#fff' },
  medium: { bg: '#c58c00', color: '#fff' },
  low: { bg: '#2b9af3', color: '#fff' },
  info: { bg: '#6a6e73', color: '#fff' },
};

const CATEGORY_LABELS: Record<string, string> = {
  lint: 'Lint',
  modernize: 'Modernize',
  risk: 'Risk',
  policy: 'Policy',
  secrets: 'Secrets',
  dependencies: 'Dependencies',
};

const useStyles = makeStyles(theme => {
  const isDark = theme.palette.type === 'dark';
  return {
    dialogPaper: {
      maxWidth: 680,
      width: '100%',
      borderRadius: 12,
      overflow: 'hidden',
    },
    header: {
      display: 'flex',
      alignItems: 'flex-start',
      justifyContent: 'space-between',
      padding: '20px 24px 16px',
      borderBottom: `1px solid ${theme.palette.divider}`,
    },
    body: {
      padding: '0 24px 24px',
      maxHeight: '60vh',
      overflowY: 'auto' as const,
    },
    violationRow: {
      padding: '12px 0',
      borderBottom: `1px solid ${theme.palette.divider}`,
      '&:last-child': { borderBottom: 'none' },
    },
    severityChip: {
      display: 'inline-block',
      padding: '2px 8px',
      borderRadius: 3,
      fontSize: 10,
      fontWeight: 600,
      textTransform: 'uppercase' as const,
      letterSpacing: 0.3,
      flexShrink: 0,
    },
    ruleId: {
      fontSize: 11,
      fontFamily: "'SF Mono', 'Fira Code', monospace",
      color: theme.palette.text.secondary,
      backgroundColor: isDark ? 'rgba(255,255,255,0.08)' : '#f0f0f0',
      padding: '1px 5px',
      borderRadius: 3,
      flexShrink: 0,
    },
    message: {
      fontSize: 13,
      color: theme.palette.text.primary,
      flex: 1,
    },
    detail: {
      padding: '8px 0 4px 0',
    },
    detailDescription: {
      fontSize: 12,
      color: theme.palette.text.secondary,
      lineHeight: 1.5,
      marginBottom: 8,
    },
    codeBlock: {
      fontFamily: "'SF Mono', 'Fira Code', 'JetBrains Mono', monospace",
      fontSize: 11,
      lineHeight: 1.6,
      backgroundColor: isDark ? '#0d1117' : '#f6f8fa',
      border: `1px solid ${isDark ? 'rgba(255,255,255,0.1)' : '#e1e4e8'}`,
      borderRadius: 4,
      overflow: 'hidden',
      marginBottom: 8,
    },
    codeLine: {
      display: 'flex',
      padding: '0 12px',
    },
    codeLineNum: {
      width: 28,
      textAlign: 'right' as const,
      color: isDark ? '#484f58' : '#8b949e',
      paddingRight: 12,
      userSelect: 'none' as const,
      flexShrink: 0,
    },
    codeLineText: {
      flex: 1,
      color: isDark ? '#c9d1d9' : '#24292f',
      whiteSpace: 'pre' as const,
    },
    codeLineHighlighted: {
      backgroundColor: isDark ? 'rgba(201, 25, 11, 0.15)' : 'rgba(201, 25, 11, 0.08)',
    },
    detailMeta: {
      display: 'flex',
      gap: 16,
      fontSize: 11,
      color: theme.palette.text.secondary,
      flexWrap: 'wrap' as const,
    },
    detailMetaItem: {
      display: 'inline-flex',
      alignItems: 'center',
      gap: 4,
    },
    fileLink: {
      fontSize: 11,
      fontFamily: "'SF Mono', 'Fira Code', monospace",
      color: theme.palette.primary.main,
      cursor: 'pointer',
      textDecoration: 'none',
      '&:hover': { textDecoration: 'underline' },
    },
    acknowledgeBtn: {
      fontSize: 11,
      textTransform: 'none' as const,
      padding: '3px 12px',
      minWidth: 0,
      borderRadius: 20,
      color: theme.palette.text.secondary,
      borderColor: theme.palette.divider,
      '&:hover': {
        backgroundColor: isDark ? 'rgba(255,255,255,0.04)' : 'rgba(0,0,0,0.04)',
      },
    },
    acknowledgedRow: {
      opacity: 0.5,
    },
    footer: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      padding: '12px 24px',
      borderTop: `1px solid ${theme.palette.divider}`,
      backgroundColor: isDark ? 'rgba(255,255,255,0.02)' : '#fafafa',
    },
  };
});

export interface ViolationDetailModalProps {
  open: boolean;
  onClose: () => void;
  title: string;
  subtitle?: string;
  violations: QualityViolation[];
  totalProjectViolations?: number;
  projectName?: string;
  onNavigateToQuality?: (category?: string, rule?: string) => void;
  repoUrl?: string;
  branch?: string;
}

export function ViolationDetailModal({
  open,
  onClose,
  title,
  subtitle,
  violations,
  totalProjectViolations,
  projectName,
  onNavigateToQuality,
  repoUrl,
  branch,
}: ViolationDetailModalProps) {
  const classes = useStyles();
  const theme = useTheme();
  const [acknowledgedIds, setAcknowledgedIds] = useState<Set<string>>(new Set());

  const toggleAcknowledge = (key: string) => {
    setAcknowledgedIds(prev => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const getKey = (v: QualityViolation, i: number) => `${v.ruleId}:${v.file}:${v.lineStart}:${i}`;

  const sevOrder: SeverityClass[] = ['critical', 'high', 'medium', 'low', 'info'];
  const sorted = useMemo(() =>
    [...violations].sort((a, b) => sevOrder.indexOf(a.severity) - sevOrder.indexOf(b.severity)),
    [violations],
  );

  const severitySummary = useMemo(() => {
    const counts: Partial<Record<SeverityClass, number>> = {};
    for (const v of violations) {
      counts[v.severity] = (counts[v.severity] ?? 0) + 1;
    }
    return sevOrder.filter(s => (counts[s] ?? 0) > 0).map(s => ({ severity: s, count: counts[s]! }));
  }, [violations]);

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth={false}
      PaperProps={{ className: classes.dialogPaper }}
    >
      {/* Header */}
      <Box className={classes.header}>
        <Box>
          <Typography style={{ fontSize: 16, fontWeight: 600, marginBottom: 4 }}>
            {title}
          </Typography>
          {subtitle && (
            <Typography style={{ fontSize: 12, color: theme.palette.text.secondary }}>
              {subtitle}
            </Typography>
          )}
          <Box display="flex" alignItems="center" style={{ gap: 8, marginTop: 8 }}>
            {severitySummary.map(({ severity, count }) => {
              const sev = FILLED_SEVERITY[severity];
              return (
                <span
                  key={severity}
                  style={{
                    fontSize: 11,
                    fontWeight: 600,
                    padding: '1px 7px',
                    borderRadius: 3,
                    backgroundColor: sev.bg,
                    color: sev.color,
                    textTransform: 'capitalize',
                  }}
                >
                  {count} {severity}
                </span>
              );
            })}
          </Box>
        </Box>
        <IconButton size="small" onClick={onClose} style={{ marginTop: -4 }}>
          <CloseIcon style={{ fontSize: 18 }} />
        </IconButton>
      </Box>

      {/* Violation rows — no drawer, info shown directly */}
      <Box className={classes.body}>
        {sorted.map((v, i) => {
          const key = getKey(v, i);
          const isAcknowledged = acknowledgedIds.has(key);
          const sevStyle = FILLED_SEVERITY[v.severity] || FILLED_SEVERITY.info;

          return (
            <Box key={key} className={`${classes.violationRow} ${isAcknowledged ? classes.acknowledgedRow : ''}`}>
              <Box display="flex" alignItems="center" style={{ gap: 10, marginBottom: 8 }}>
                <span className={classes.severityChip} style={{ backgroundColor: sevStyle.bg, color: sevStyle.color }}>
                  {v.severity}
                </span>
                <span className={classes.ruleId}>{v.ruleId}</span>
                <span className={classes.message}>{v.message}</span>
              </Box>

              <Typography className={classes.detailDescription}>
                {v.ruleDescription}
              </Typography>

              {DEMO_CODE_CONTEXT[v.ruleId] && (
                <Box className={classes.codeBlock}>
                  {DEMO_CODE_CONTEXT[v.ruleId].lines.map((line, li) => (
                    <Box
                      key={li}
                      className={`${classes.codeLine} ${line.highlighted ? classes.codeLineHighlighted : ''}`}
                    >
                      <span className={classes.codeLineNum}>{line.num}</span>
                      <span className={classes.codeLineText}>{line.text}</span>
                    </Box>
                  ))}
                </Box>
              )}

              {DEMO_CODE_CONTEXT[v.ruleId]?.detail && (
                <Typography className={classes.detailDescription}>
                  {DEMO_CODE_CONTEXT[v.ruleId].detail}
                </Typography>
              )}

              <Box display="flex" alignItems="center" justifyContent="space-between" style={{ gap: 8 }}>
                <Box className={classes.detailMeta}>
                  <span className={classes.detailMetaItem}>
                    <a
                      className={classes.fileLink}
                      href="#"
                      onClick={(e) => {
                        e.preventDefault();
                        if (repoUrl) window.open(`${repoUrl}/blob/${branch ?? 'main'}/${v.file}#L${v.lineStart}`, '_blank');
                      }}
                    >
                      {v.file}:{v.lineStart}
                      <OpenInNewIcon style={{ fontSize: 10, marginLeft: 2, verticalAlign: 'middle', opacity: 0.6 }} />
                    </a>
                  </span>
                  <span className={classes.detailMetaItem}>
                    Category: <strong>{CATEGORY_LABELS[v.category] ?? v.category}</strong>
                  </span>
                  <span className={classes.detailMetaItem}>
                    Validator: <strong>{v.validatorSource}</strong>
                  </span>
                </Box>
                <Box display="flex" alignItems="center" style={{ gap: 6, flexShrink: 0 }}>
                  <Tooltip title="Dismiss — remove from results" arrow>
                    <Button
                      variant="outlined"
                      size="small"
                      className={classes.acknowledgeBtn}
                      startIcon={<VisibilityOffOutlinedIcon style={{ fontSize: 13 }} />}
                      onClick={(e) => { e.stopPropagation(); toggleAcknowledge(key); }}
                    >
                      Dismiss
                    </Button>
                  </Tooltip>
                  <Tooltip title="Edit in Dev Spaces" arrow>
                    <IconButton
                      size="small"
                      onClick={(e) => {
                        e.stopPropagation();
                        window.open(`/devspaces-mockup.html?state=edit&file=${encodeURIComponent(v.file)}&line=${v.lineStart}&rule=${encodeURIComponent(v.ruleId)}`, '_blank');
                      }}
                      style={{ padding: 4, border: `1px solid ${theme.palette.divider}`, borderRadius: 20 }}
                    >
                      <CodeIcon style={{ fontSize: 14, color: theme.palette.primary.main }} />
                    </IconButton>
                  </Tooltip>
                </Box>
              </Box>
            </Box>
          );
        })}
      </Box>

      {/* Footer */}
      <Box className={classes.footer}>
        <Typography style={{ fontSize: 12, color: theme.palette.text.secondary }}>
          {violations.length} of {totalProjectViolations ?? violations.length} violation{(totalProjectViolations ?? violations.length) !== 1 ? 's' : ''}
          {projectName && ` in ${projectName}`}
          {acknowledgedIds.size > 0 && ` · ${acknowledgedIds.size} acknowledged`}
        </Typography>
        {onNavigateToQuality && (
          <Button
            size="small"
            variant="outlined"
            color="primary"
            onClick={() => {
              onClose();
              onNavigateToQuality(undefined);
            }}
            style={{ textTransform: 'none', fontSize: 12, fontWeight: 500, borderRadius: 20 }}
          >
            View all {totalProjectViolations ?? violations.length} violations →
          </Button>
        )}
      </Box>
    </Dialog>
  );
}
