// @ts-nocheck
import { useMemo, useState } from 'react';
import {
  Box,
  Typography,
  Tooltip,
  makeStyles,
  useTheme,
} from '@material-ui/core';
import CheckCircleOutlineIcon from '@material-ui/icons/CheckCircleOutline';
import HelpOutlineIcon from '@material-ui/icons/HelpOutline';
import {
  type ProjectQualityData,
  type QualityViolation,
  type SeverityClass,
  SEVERITY_COLORS,
} from './qualityDemoData';
import { ViolationDetailModal } from './ViolationDetailModal';

const useStyles = makeStyles(theme => ({
  root: {
    padding: '24px 0',
  },
  sectionTitle: {
    fontSize: 14,
    fontWeight: 600,
    marginBottom: 12,
    marginTop: 8,
    color: theme.palette.text.primary,
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse' as const,
    fontSize: 13,
    '& th': {
      textAlign: 'left',
      padding: '8px 12px',
      fontWeight: 600,
      fontSize: 11,
      textTransform: 'uppercase',
      letterSpacing: 0.5,
      color: theme.palette.text.secondary,
      borderBottom: `2px solid ${theme.palette.divider}`,
    },
    '& td': {
      padding: '8px 12px',
      borderBottom: `1px solid ${theme.palette.divider}`,
      verticalAlign: 'middle',
    },
  },
  sourceBadge: {
    fontSize: 10,
    fontWeight: 600,
    textTransform: 'uppercase' as const,
    padding: '1px 6px',
    borderRadius: 3,
    letterSpacing: 0.3,
  },
  noData: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: 40,
    color: theme.palette.text.secondary,
    fontSize: 14,
    gap: 8,
  },
}));

const SOURCE_COLORS: Record<string, { bg: string; color: string }> = {
  specified: { bg: '#e7f1fa', color: '#0066cc' },
  dependency: { bg: '#f4f0e6', color: '#795600' },
  learned: { bg: '#e9f5e9', color: '#3e8635' },
};

interface DependenciesTabProps {
  quality: ProjectQualityData | null;
  projectName: string;
  onNavigateToQuality?: (category?: string, rule?: string) => void;
  repoUrl?: string;
  branch?: string;
}

type ModalTarget = {
  title: string;
  subtitle?: string;
  violations: QualityViolation[];
} | null;

export function DependenciesTab({ quality, projectName, onNavigateToQuality, repoUrl, branch }: DependenciesTabProps) {
  const classes = useStyles();
  const theme = useTheme();
  const [modalTarget, setModalTarget] = useState<ModalTarget>(null);

  const depViolations = useMemo(
    () => (quality?.violations ?? []).filter(v => v.category === 'dependencies'),
    [quality],
  );

  if (!quality) {
    return (
      <Box className={classes.noData}>
        <Typography>No scan data available</Typography>
      </Box>
    );
  }

  const collections = useMemo(
    () => [...(quality.collections ?? [])].sort((a, b) => b.violations - a.violations),
    [quality],
  );

  const pythonPkgs = useMemo(
    () => [...(quality.pythonPackages ?? [])].sort((a, b) => b.cveCount - a.cveCount),
    [quality],
  );

  const totalIssues = collections.reduce((s, c) => s + c.violations, 0)
    + pythonPkgs.reduce((s, p) => s + p.cveCount, 0);

  return (
    <Box className={classes.root}>
      {/* Summary line */}
      <Box display="flex" alignItems="center" style={{ gap: 10, marginBottom: 6 }}>
        <Typography style={{ fontSize: 13 }}>
          <strong>{collections.length}</strong> collection{collections.length !== 1 ? 's' : ''}
          {' · '}
          <strong>{pythonPkgs.length}</strong> Python package{pythonPkgs.length !== 1 ? 's' : ''}
        </Typography>
        {totalIssues > 0 && (
          <>
            <span style={{ color: theme.palette.divider }}>|</span>
            <span style={{
              fontSize: 11,
              fontWeight: 600,
              padding: '1px 7px',
              borderRadius: 10,
              backgroundColor: `${SEVERITY_COLORS.high}15`,
              color: SEVERITY_COLORS.high,
            }}>
              {totalIssues} with violations
            </span>
          </>
        )}
      </Box>

      {/* Provenance */}
      <Box display="flex" alignItems="center" style={{ gap: 6, marginBottom: 20 }}>
        <Typography style={{ fontSize: 12, color: theme.palette.text.secondary }}>
          Discovered from latest{' '}
          <Tooltip title="Go to Quality tab" arrow>
            <span
              onClick={onNavigateToQuality ? () => onNavigateToQuality() : undefined}
              style={{
                textDecoration: 'underline',
                textUnderlineOffset: 2,
                cursor: onNavigateToQuality ? 'pointer' : 'default',
                color: theme.palette.text.secondary,
              }}
            >
              quality scan
            </span>
          </Tooltip>
          {' '}· {quality.lastScannedAt}
        </Typography>
        <Tooltip
          title="Quality scans automatically analyze this repository's code and requirements files to detect collections, Python packages, and known issues such as vulnerabilities or compatibility concerns."
          arrow
          placement="bottom-start"
        >
          <HelpOutlineIcon style={{ fontSize: 14, color: theme.palette.text.secondary, opacity: 0.5, cursor: 'help' }} />
        </Tooltip>
      </Box>

      {/* Collections table */}
      <Typography className={classes.sectionTitle}>
        Collections ({collections.length})
      </Typography>
      <Box style={{ border: `1px solid ${theme.palette.divider}`, borderRadius: 6, overflow: 'hidden', marginBottom: 24 }}>
        <table className={classes.table}>
          <thead>
            <tr>
              <th><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>FQCN <Tooltip title="Fully Qualified Collection Name — the unique identifier for an Ansible collection" arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
              <th><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>Version <Tooltip title="The version of this collection detected in the repository" arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
              <th><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>Source <Tooltip title="How this collection was detected: specified in requirements, pulled as a dependency of another collection, or learned from usage in code" arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
              <th style={{ textAlign: 'right' }}><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4, justifyContent: 'flex-end' }}>Violations <Tooltip title="Number of issues found in this collection during the latest quality scan. Click the count to view details." arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
            </tr>
          </thead>
          <tbody>
            {collections.map(c => {
              const srcStyle = SOURCE_COLORS[c.source] || SOURCE_COLORS.specified;
              return (
                <tr key={c.fqcn}>
                  <td>
                    <Typography style={{ fontFamily: 'monospace', fontSize: 13, fontWeight: 500 }}>
                      {c.fqcn}
                    </Typography>
                  </td>
                  <td>
                    <Typography style={{ fontFamily: 'monospace', fontSize: 12, color: theme.palette.text.secondary }}>
                      {c.version}
                    </Typography>
                  </td>
                  <td>
                    <span className={classes.sourceBadge} style={{ backgroundColor: srcStyle.bg, color: srcStyle.color }}>
                      {c.source}
                    </span>
                  </td>
                  <td style={{ textAlign: 'right' }}>
                    {c.violations > 0 ? (
                      <span
                        onClick={() => {
                          const matched = depViolations.filter(v => v.yamlPath === c.fqcn);
                          setModalTarget({
                            title: `${matched.length} violation${matched.length !== 1 ? 's' : ''} in ${c.fqcn}`,
                            subtitle: `${c.fqcn} ${c.version} · ${c.source}`,
                            violations: matched,
                          });
                        }}
                        style={{
                          display: 'inline-block',
                          fontSize: 11,
                          fontWeight: 600,
                          padding: '1px 7px',
                          borderRadius: 10,
                          backgroundColor: `${SEVERITY_COLORS.high}15`,
                          color: SEVERITY_COLORS.high,
                          cursor: 'pointer',
                        }}
                      >
                        {c.violations}
                      </span>
                    ) : (
                      <CheckCircleOutlineIcon style={{ fontSize: 16, color: '#3e8635', opacity: 0.6 }} />
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </Box>

      {/* Python packages table */}
      <Typography className={classes.sectionTitle}>
        Python packages ({pythonPkgs.length})
      </Typography>
      <Box style={{ border: `1px solid ${theme.palette.divider}`, borderRadius: 6, overflow: 'hidden', marginBottom: 24 }}>
        <table className={classes.table}>
          <thead>
            <tr>
              <th><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>Package <Tooltip title="The Python package name as listed in requirements" arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
              <th><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>Version <Tooltip title="The version of this package detected in the repository" arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
              <th style={{ textAlign: 'right' }}><span style={{ display: 'inline-flex', alignItems: 'center', gap: 4, justifyContent: 'flex-end' }}>Violations <Tooltip title="Number of known vulnerabilities (CVEs) found for this package version. Click the count to view details." arrow><HelpOutlineIcon style={{ fontSize: 12, opacity: 0.4, cursor: 'help' }} /></Tooltip></span></th>
            </tr>
          </thead>
          <tbody>
            {pythonPkgs.map(p => (
              <tr key={p.name}>
                <td>
                  <Typography style={{ fontFamily: 'monospace', fontSize: 13, fontWeight: 500 }}>
                    {p.name}
                  </Typography>
                </td>
                <td>
                  <Typography style={{ fontFamily: 'monospace', fontSize: 12, color: theme.palette.text.secondary }}>
                    {p.version}
                  </Typography>
                </td>
                <td style={{ textAlign: 'right' }}>
                  {p.cveCount > 0 ? (
                    <span
                      onClick={() => {
                        const matched = depViolations.filter(v => v.yamlPath === p.name);
                        setModalTarget({
                          title: `${matched.length} vulnerability${matched.length !== 1 ? 'ies' : ''} in ${p.name}`,
                          subtitle: `${p.name} ${p.version}`,
                          violations: matched,
                        });
                      }}
                      style={{
                        display: 'inline-block',
                        fontSize: 11,
                        fontWeight: 600,
                        padding: '1px 7px',
                        borderRadius: 10,
                        backgroundColor: `${(p.highestSeverity ? SEVERITY_COLORS[p.highestSeverity] : SEVERITY_COLORS.medium)}15`,
                        color: p.highestSeverity ? SEVERITY_COLORS[p.highestSeverity] : SEVERITY_COLORS.medium,
                        cursor: 'pointer',
                      }}
                    >
                      {p.cveCount}
                    </span>
                  ) : (
                    <CheckCircleOutlineIcon style={{ fontSize: 16, color: '#3e8635', opacity: 0.6 }} />
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </Box>

      {/* All healthy state */}
      {totalIssues === 0 && (
        <Box className={classes.noData} style={{ marginTop: -8 }}>
          <CheckCircleOutlineIcon style={{ fontSize: 20, color: '#3e8635' }} />
          <Typography>All dependencies are healthy.</Typography>
        </Box>
      )}

      {/* Violation detail modal */}
      <ViolationDetailModal
        open={!!modalTarget}
        onClose={() => setModalTarget(null)}
        title={modalTarget?.title ?? ''}
        subtitle={modalTarget?.subtitle}
        violations={modalTarget?.violations ?? []}
        totalProjectViolations={quality?.violations.length}
        projectName={projectName}
        onNavigateToQuality={onNavigateToQuality}
        repoUrl={repoUrl}
        branch={branch}
      />
    </Box>
  );
}
